patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp b/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
index 75e7c1c97018..3c762b1f89b8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
@@ -2902,8 +2902,38 @@ Instruction *InstCombinerImpl::visitShuffleVectorInst(ShuffleVectorInst &SVI) {

   if (match(RHS, m_Constant())) {
     if (auto *SI = dyn_cast<SelectInst>(LHS)) {
-      if (Instruction *I = FoldOpIntoSelect(SVI, SI))
-        return I;
+      // Check that folding the shuffle into the select won't create an invalid
+      // select instruction. For vector selects, the condition vector and the
+      // selected value vectors must have the same number of elements.
+      Type *CondTy = SI->getCondition()->getType();
+      Type *ResultTy = SVI.getType();
+      
+      bool SafeToFold = true;
+      if (CondTy->isVectorTy() && ResultTy->isVectorTy()) {
+        FixedVectorType *CondVecTy = cast<FixedVectorType>(CondTy);
+        FixedVectorType *ResultVecTy = cast<FixedVectorType>(ResultTy);
+        if (CondVecTy->getNumElements() != ResultVecTy->getNumElements()) {
+          SafeToFold = false;
+        }
+      }
+      
+      // Additionally, only allow folding if the shuffle only uses elements from LHS.
+      // This prevents issues with shuffles that combine LHS and RHS elements.
+      if (SafeToFold) {
+        ArrayRef<int> Mask = SVI.getShuffleMask();
+        unsigned LHSWidth = cast<FixedVectorType>(LHS->getType())->getNumElements();
+        for (int Idx : Mask) {
+          if (Idx >= (int)LHSWidth && Idx != -1) {
+            SafeToFold = false;
+            break;
+          }
+        }
+      }
+      
+      if (SafeToFold) {
+        if (Instruction *I = FoldOpIntoSelect(SVI, SI))
+          return I;
+      }
     }
     if (auto *PN = dyn_cast<PHINode>(LHS)) {
       if (Instruction *I = foldOpIntoPhi(SVI, PN))

